#include <bits/stdc++.h>
using namespace std;
int n,m,a[2502][2502],dp[2502][2502],s[2502][2502],ans;
int sum(int x,int y,int u,int v){
    if(x>u || y>v)
        return 0;
    return s[u][v]-s[u][y-1]-s[x-1][v]+s[x-1][y-1];
}
int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
        for(int j=1;j<=m;j++){
            scanf("%d",&a[i][j]);
            s[i][j]=a[i][j]+s[i-1][j]+s[i][j-1]-s[i-1][j-1];
        }
    for(int i=1;i<=n;i++)
        for(int j=1;j<=m;j++)
            if(a[i][j]==1){
                int l=0,r=dp[i-1][j-1];
                while(l<r){
                    int mid=(l+r+1)/2;
                    if(sum(i,j-mid,i,j)==1 && sum(i-mid,j,i,j)==1)
                        l=mid;
                    else
                        r=mid-1;
                }
                dp[i][j]=l+1;
                ans=max(ans,dp[i][j]);
            }
    memset(dp,0,sizeof(dp));
    for(int i=1;i<=n;i++)
        for(int j=m;j;j--)
            if(a[i][j]==1){
                int l=0,r=dp[i-1][j+1];
                while(l<r){
                    int mid=(l+r+1)/2;
                    if(sum(i,j,i,j+mid)==1 && sum(i-mid,j,i,j)==1)
                        l=mid;
                    else
                        r=mid-1;
                }
                dp[i][j]=l+1;
                ans=max(ans,dp[i][j]);
            }
    printf("%d",ans);
    return 0;
}
